sql:
SELECT owner_id, COUNT(*) AS total_signals
FROM signals
GROUP BY owner_id;

SELECT sd.doc_file, sd.doc_size, sd.upload_date, sd.version, sd.created_at, sd.updated_at, sd.deprecated_at
FROM signal_documentation sd
WHERE sd.signal_id = 1;

SELECT signal_id, signal_name, updated_at
FROM signals
WHERE signal_id IS NOT NULL;

SELECT
  (SELECT COUNT(*) FROM signals WHERE owner_id = 1) AS signal_count,
  (SELECT COUNT(*) FROM signal_documentation WHERE owner_id = 1) AS documentation_count;

SELECT signal_id, signal_name, init_status_id
FROM signals
WHERE init_status_id = '0';

SELECT interface_name, owner_id
FROM interfaces
WHERE interface_id IN (0, 1);

SELECT signal_name
FROM signals
WHERE owner_id = 0;

